// Récupérer les items du dossier template rapport
const items = $input.all();

// Si aucun item
if (!items || items.length === 0 || !items[0].json || Object.keys(items[0].json).length === 0) {
  return [{
    json: {
      success: true,
      timestamp: new Date().toISOString(),
      dossier: "template rapport",
      message: "Dossier vide ou non trouvé",
      statistiques: {
        totalDossiers: 0,
        totalFichiers: 0
      },
      contenu: {
        sousDossiers: [],
        fichiers: []
      }
    }
  }];
}

// Séparer dossiers et fichiers
const sousDossiers = [];
const fichiers = [];

for (const item of items) {
  const data = item.json;
  if (!data || !data.id) continue;

  if (data.mimeType === 'application/vnd.google-apps.folder') {
    sousDossiers.push({
      id: data.id,
      nom: data.name || 'Sans nom',
      type: 'dossier',
      mimeType: data.mimeType
    });
  } else {
    fichiers.push({
      id: data.id,
      nom: data.name || 'Sans nom',
      type: 'fichier',
      mimeType: data.mimeType || 'unknown'
    });
  }
}

return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    dossier: "template rapport",
    statistiques: {
      totalSousDossiers: sousDossiers.length,
      totalFichiers: fichiers.length,
      totalElements: sousDossiers.length + fichiers.length
    },
    contenu: {
      sousDossiers: sousDossiers,
      fichiers: fichiers
    }
  }
}];
